1	export type Cell = [number, number];
2	
3	const NEIGHBOR_OFFSETS: ReadonlyArray<readonly [number, number]> = [
4	  [-1, -1], [-1, 0], [-1, 1],
5	  [ 0, -1],          [ 0, 1],
6	  [ 1, -1], [ 1, 0], [ 1, 1],
7	];
8	
9	const toKey = (x: number, y: number): string => `${x},${y}`;
10	const fromKey = (key: string): Cell => {
11	  const [x, y] = key.split(",").map(Number);
12	  return [x, y];
13	};
14	
15	export function nextGeneration(cells: Cell[]): Cell[] {
16	  const aliveKeys = new Set(cells.map(([x, y]) => toKey(x, y)));
17	
18	  const neighborCounts = new Map<string, number>();
19	  for (const [x, y] of cells) {
20	    for (const [dx, dy] of NEIGHBOR_OFFSETS) {
21	      const neighborKey = toKey(x + dx, y + dy);
22	      neighborCounts.set(neighborKey, (neighborCounts.get(neighborKey) ?? 0) + 1);
23	    }
24	  }
25	
26	  const survivesOrIsBorn = (cellKey: string, count: number): boolean =>
27	    count === 3 || (count === 2 && aliveKeys.has(cellKey));
28	
29	  const result: Cell[] = [];
30	  for (const [cellKey, count] of neighborCounts) {
31	    if (survivesOrIsBorn(cellKey, count)) {
32	      result.push(fromKey(cellKey));
33	    }
34	  }
35	  return result;
36	}
