1	import { describe, it, expect } from "vitest";
2	import { nextGeneration, type Cell } from "./game-of-life.js";
3	
4	describe("Conway's Game of Life - nextGeneration", () => {
5	  it("should return an empty array for an empty input", () => {
6	    const input: Cell[] = [];
7	    expect(nextGeneration(input)).toEqual([]);
8	  });
9	  it("should return an empty array for a single live cell (underpopulation)", () => {
10	    const input: Cell[] = [[0, 0]];
11	    expect(nextGeneration(input)).toEqual([]);
12	  });
13	  it("should return an empty array for two adjacent live cells (underpopulation)", () => {
14	    const input: Cell[] = [[0, 1], [1, 1]];
15	    expect(nextGeneration(input)).toEqual([]);
16	  });
17	  it("should keep a 2x2 block unchanged (still life)", () => {
18	    const input: Cell[] = [[0, 0], [1, 0], [0, 1], [1, 1]];
19	    const result = nextGeneration(input);
20	    expect(result).toHaveLength(4);
21	    expect(result).toEqual(expect.arrayContaining(input));
22	  });
23	  it("should transform a vertical blinker into a horizontal blinker", () => {
24	    const input: Cell[] = [[0, 0], [0, 1], [0, 2]];
25	    const expected: Cell[] = [[-1, 1], [0, 1], [1, 1]];
26	    const result = nextGeneration(input);
27	    expect(result).toHaveLength(3);
28	    expect(result).toEqual(expect.arrayContaining(expected));
29	  });
30	  it("should kill the center cell of a 3x3 full block (overpopulation)", () => {
31	    const input: Cell[] = [[0, 0], [1, 0], [2, 0], [0, 1], [1, 1], [2, 1], [0, 2], [1, 2], [2, 2]];
32	    const expected: Cell[] = [[0, 0], [2, 0], [0, 2], [2, 2], [-1, 1], [3, 1], [1, -1], [1, 3]];
33	    const result = nextGeneration(input);
34	    expect(result).toHaveLength(8);
35	    expect(result).toEqual(expect.arrayContaining(expected));
36	  });
37	  it("should bring a dead cell to life when it has exactly 3 live neighbors (reproduction)", () => {
38	    const input: Cell[] = [[0, 0], [1, 0], [0, 1]];
39	    const expected: Cell[] = [[0, 0], [1, 0], [0, 1], [1, 1]];
40	    const result = nextGeneration(input);
41	    expect(result).toHaveLength(4);
42	    expect(result).toEqual(expect.arrayContaining(expected));
43	  });
44	});
